from flask import Flask, render_template, request, jsonify
import random

app = Flask(__name__)

@app.route("/body")
def open_main_article():
    action = request.args.get("action")
    sector_type = request.args.get("sector_type")
    funds = request.args.get("funds")
    allowance = request.args.get("allowance")

    result = "This is the body of the article"

    if action == "lend":
        result = f"You're lending your funds! You lent ${funds}."
    elif action == "borrow":
        result = f"You're borrowing funds! You have a limit of ${funds}."

    return "<p>" + result + "</p>"

@app.route('/form')
def form():
    return render_template('form.html')

class FundManager(object):
    __slots__ = ['funds']

    def __init__(self, funds):
        self.funds = funds

    def calculate_max_withdrawal(self):
        return self.funds

class HighValueFundManager(FundManager):
    def __init__(self, funds, allowance):
        self.funds = funds
        self.allowance = allowance

    def calculate_max_withdrawal(self):
        if self.funds > self.allowance:
            funds_available = self.allowance
        else:
            funds_available = self.funds
        return super().calculate_max_withdrawal(funds_available)

@app.route('/spend_form', methods=['POST'])
def spend_form():
    amount = request.form.get('amount')
    sector_type = request.form.get('sector_type')
    funds = request.form.get('funds')
    allowance = request.form.get('allowance')
    val1 = request.form.get('val1')
    val2 = request.form.get('val2')
    val3 = request.form.get('val3')
    val4 = request.form.get('val4')
    result = "Error: Cannot spend money"
    if amount and funds and sector_type:
        fund_manager = HighValueFundManager(funds, allowance)
        spend_amount = fund_manager.calculate_max_withdrawal()
        print(spend_amount)
        result = f"You spent ${spend_amount}."

    return result

if __name__ == '__main__':
    app.run()
